### Initialize Supabase SSR Client with Custom Cookie Handlers

Source: https://context7.com/supabase/ssr/llms.txt

This collection of examples demonstrates how to use `createServerClient` from `@supabase/ssr` to create a Supabase client for server-side rendering contexts. It provides specific implementations for handling cookies in Next.js (middleware, server components, route handlers) and SvelteKit, ensuring proper session management and authentication on the server.

```typescript
import { createServerClient } from '@supabase/ssr'
import { cookies } from 'next/headers'

// Next.js App Router - Middleware (recommended pattern)
export async function middleware(request: NextRequest) {
  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) => {
            request.cookies.set(name, value)
          })
          const response = NextResponse.next({ request })
          cookiesToSet.forEach(({ name, value, options }) => {
            response.cookies.set(name, value, options)
          })
          return response
        }
      }
    }
  )

  // Automatically refreshes expired sessions
  const { data: { session } } = await supabase.auth.getSession()

  if (!session && request.nextUrl.pathname.startsWith('/dashboard')) {
    return NextResponse.redirect(new URL('/login', request.url))
  }

  return response
}
```

```typescript
// Next.js App Router - Server Component (read-only)
export default async function Page() {
  const cookieStore = cookies()

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          // Warning will be logged if mutations occur
          // Always use middleware for session refresh
        }
      }
    }
  )

  const { data: { user } } = await supabase.auth.getUser()
  const { data: posts } = await supabase
    .from('posts')
    .select('*')
    .eq('user_id', user?.id)

  return <div>Welcome {user?.email}, you have {posts?.length} posts</div>
}
```

```typescript
// Next.js App Router - Route Handler (with mutations)
export async function POST(request: Request) {
  const cookieStore = cookies()

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) => {
            cookieStore.set(name, value, options)
          })
        }
      }
    }
  )

  const { error } = await supabase.auth.updateUser({
    data: { display_name: 'New Name' }
  })

  return Response.json({ success: !error })
}
```

```typescript
// SvelteKit - hooks.server.ts
export const handle = async ({ event, resolve }) => {
  event.locals.supabase = createServerClient(
    import.meta.env.VITE_SUPABASE_URL,
    import.meta.env.VITE_SUPABASE_ANON_KEY,
    {
      cookies: {
        getAll: () => {
          return event.cookies.getAll().map(({ name, value }) => ({
            name,
            value
          }))
        },
        setAll: (cookiesToSet) => {
          cookiesToSet.forEach(({ name, value, options }) => {
            event.cookies.set(name, value, options)
          })
        }
      }
    }
  )

  return resolve(event)
}
